/**
 * Number formatting utilities for data display components.
 */

export interface FormatNumberOptions {
  /** Locale for formatting (default: 'en-NZ') */
  locale?: string;
  /** Number style */
  style?: 'decimal' | 'currency' | 'percent';
  /** Currency code (only for style: 'currency') */
  currency?: string;
  /** Minimum fraction digits */
  minimumFractionDigits?: number;
  /** Maximum fraction digits */
  maximumFractionDigits?: number;
  /** Notation style */
  notation?: 'standard' | 'compact';
}

/**
 * Format a number with Intl.NumberFormat.
 */
export function formatNumber(
  value: number | null | undefined,
  options: FormatNumberOptions = {}
): string {
  if (value == null || isNaN(value)) return '';

  const {
    locale = 'en-NZ',
    style = 'decimal',
    currency = 'NZD',
    minimumFractionDigits,
    maximumFractionDigits,
    notation = 'standard',
  } = options;

  return new Intl.NumberFormat(locale, {
    style,
    currency: style === 'currency' ? currency : undefined,
    minimumFractionDigits,
    maximumFractionDigits,
    notation,
  }).format(value);
}

/**
 * Format a number as currency.
 */
export function formatCurrency(
  value: number | null | undefined,
  options: Omit<FormatNumberOptions, 'style'> = {}
): string {
  return formatNumber(value, {
    ...options,
    style: 'currency',
    minimumFractionDigits: options.minimumFractionDigits ?? 2,
    maximumFractionDigits: options.maximumFractionDigits ?? 2,
  });
}

/**
 * Format a number as percentage.
 * @param value - Value between 0 and 1 (e.g., 0.75 for 75%)
 */
export function formatPercent(
  value: number | null | undefined,
  options: Omit<FormatNumberOptions, 'style'> = {}
): string {
  return formatNumber(value, {
    ...options,
    style: 'percent',
    minimumFractionDigits: options.minimumFractionDigits ?? 0,
    maximumFractionDigits: options.maximumFractionDigits ?? 1,
  });
}

/**
 * Format a number in compact notation (e.g., 1.2K, 3.4M).
 */
export function formatCompact(
  value: number | null | undefined,
  options: Omit<FormatNumberOptions, 'notation'> = {}
): string {
  return formatNumber(value, {
    ...options,
    notation: 'compact',
    maximumFractionDigits: options.maximumFractionDigits ?? 1,
  });
}

export interface FormatDateOptions {
  /** Locale for formatting (default: 'en-NZ') */
  locale?: string;
  /** Date format style */
  dateStyle?: 'full' | 'long' | 'medium' | 'short';
  /** Time format style */
  timeStyle?: 'full' | 'long' | 'medium' | 'short';
}

/**
 * Format a date value.
 */
export function formatDate(
  value: Date | string | number | null | undefined,
  options: FormatDateOptions = {}
): string {
  if (value == null) return '';

  const date = value instanceof Date ? value : new Date(value);
  if (isNaN(date.getTime())) return '';

  const { locale = 'en-NZ', dateStyle = 'medium', timeStyle } = options;

  return new Intl.DateTimeFormat(locale, {
    dateStyle,
    timeStyle,
  }).format(date);
}

/**
 * Format a date as relative time (e.g., "2 hours ago").
 */
export function formatRelativeTime(
  value: Date | string | number | null | undefined,
  options: { locale?: string } = {}
): string {
  if (value == null) return '';

  const date = value instanceof Date ? value : new Date(value);
  if (isNaN(date.getTime())) return '';

  const { locale = 'en-NZ' } = options;
  const now = new Date();
  const diffMs = now.getTime() - date.getTime();
  const diffSec = Math.floor(diffMs / 1000);
  const diffMin = Math.floor(diffSec / 60);
  const diffHour = Math.floor(diffMin / 60);
  const diffDay = Math.floor(diffHour / 24);

  const rtf = new Intl.RelativeTimeFormat(locale, { numeric: 'auto' });

  if (diffDay > 0) return rtf.format(-diffDay, 'day');
  if (diffHour > 0) return rtf.format(-diffHour, 'hour');
  if (diffMin > 0) return rtf.format(-diffMin, 'minute');
  return rtf.format(-diffSec, 'second');
}

/**
 * Calculate percentage change between two values.
 */
export function calculateChange(
  current: number,
  previous: number
): number | null {
  if (previous === 0) return null;
  return ((current - previous) / Math.abs(previous)) * 100;
}

/**
 * Format a change value with sign (e.g., "+12.5%" or "-8.3%").
 */
export function formatChange(
  change: number | null | undefined,
  options: Omit<FormatNumberOptions, 'style'> = {}
): string {
  if (change == null) return '';

  const formatted = formatNumber(Math.abs(change), {
    ...options,
    minimumFractionDigits: options.minimumFractionDigits ?? 1,
    maximumFractionDigits: options.maximumFractionDigits ?? 1,
  });

  const sign = change > 0 ? '+' : change < 0 ? '-' : '';
  return `${sign}${formatted}%`;
}
